const config = $input.first().json || {};
const required = ['GEMINI_API_KEY', 'AIRTABLE_API_KEY', 'AIRTABLE_BASE_ID'];
const missing = required.filter((name) => !config[name] || String(config[name]).startsWith('PASTE_'));
if (missing.length) {
  throw new Error('Fill these fields in the "Open Calls Config" node: ' + missing.join(', '));
}

const BRAVE_SEARCH_API_KEY = config.BRAVE_SEARCH_API_KEY || '';
const SERPAPI_API_KEY = config.SERPAPI_API_KEY || '';
const TAVILY_API_KEY = config.TAVILY_API_KEY || '';
const GEMINI_API_KEY = config.GEMINI_API_KEY;
const AIRTABLE_API_KEY = config.AIRTABLE_API_KEY;
const AIRTABLE_BASE_ID = config.AIRTABLE_BASE_ID;
const httpRequest = this.helpers.httpRequest.bind(this);
const TODAY = new Date().toISOString().slice(0, 10);

if (!/^app[a-zA-Z0-9]+$/.test(AIRTABLE_BASE_ID)) {
  throw new Error('AIRTABLE_BASE_ID must be the Airtable base id from the base URL. It should start with "app", for example appXXXXXXXXXXXXXX. Current value: ' + AIRTABLE_BASE_ID);
}
const CONFIRMED_THRESHOLD = Number(config.OPEN_CALL_CONFIDENCE_THRESHOLD || 0.75);
const MAX_RESULTS_PER_QUERY = Number(config.OPEN_CALL_RESULTS_PER_QUERY || 8);
const MAX_CANDIDATES = Number(config.OPEN_CALL_MAX_CANDIDATES || 5);
const DISCOVERY_MODE = String(config.DISCOVERY_MODE || 'weekly').toLowerCase();
const DISCOVERY_QUERY_LIMIT = Number(config.DISCOVERY_QUERY_LIMIT || 3);
const MIN_RESULTS_BEFORE_FALLBACK = Number(config.MIN_RESULTS_BEFORE_FALLBACK || 3);
const SOURCE_RECHECK_LIMIT = Number(config.SOURCE_RECHECK_LIMIT || 10);
const DIRECT_LINK_LIMIT_PER_SOURCE = Number(config.DIRECT_LINK_LIMIT_PER_SOURCE || 8);
const AI_MODEL = config.GEMINI_MODEL || 'gemini-3.1-flash-lite';
const AI_MAX_REQUESTS_PER_RUN = Number(config.AI_MAX_REQUESTS_PER_RUN || 8);
const AI_TIME_BUDGET_MS = Number(config.AI_TIME_BUDGET_MS || 240000);
const RUN_STARTED_AT = Date.now();
let aiRequestsUsed = 0;

const searchQueries = [
  'free photography open call online submission deadline',
  'photography submissions no entry fee open call deadline',
  'international photography open call free entry photographers',
  'photo contest free entry deadline online submission',
  'museum photography open call photographers free submission',
  'gallery photography open call no entry fee deadline',
  'photography festival open call free submission deadline',
  'Picter photography open call free submission deadline',
  'PhotoVogue photography open call submissions deadline',
  'ArtConnect photography open call free entry deadline',
];

const knownSourceHints = [
  'picter.com',
  'vogue.com',
  'artconnect.com',
  'lensculture.com',
  'photocontestinsider.com',
  'photocontestdeadlines.com',
  'worldphoto.org',
  'phmuseum.com',
  'aperture.org',
  'foam.org',
];

const rejectHostFragments = [
  'facebook.com/login',
  'instagram.com/accounts/login',
  'pinterest.',
  'reddit.com',
  'x.com',
  'twitter.com',
  'youtube.com',
  'tiktok.com',
];

async function requestJson(url, options = {}) {
  const requestOptions = {
    method: options.method || 'GET',
    url,
    headers: options.headers || {},
    json: true,
  };
  if (options.body) {
    requestOptions.body = typeof options.body === 'string' ? JSON.parse(options.body) : options.body;
  }
  try {
    return await httpRequest(requestOptions);
  } catch (error) {
    throw new Error('HTTP request failed for ' + url + ': ' + (error.message || String(error)));
  }
}

function canonicalize(input) {
  let text = String(input || '').trim();
  if (!text) return '';
  text = text.split('#')[0];
  const queryIndex = text.indexOf('?');
  const base = queryIndex >= 0 ? text.slice(0, queryIndex) : text;
  const query = queryIndex >= 0 ? text.slice(queryIndex + 1) : '';
  const keptParams = [];
  const dropPrefixes = ['utm_', 'fbclid', 'gclid', 'mc_cid', 'mc_eid', 'igshid'];
  for (const part of query.split('&')) {
    if (!part) continue;
    const key = part.split('=')[0] || '';
    if (dropPrefixes.some((prefix) => key === prefix || key.startsWith(prefix))) continue;
    keptParams.push(part);
  }
  const normalizedBase = base
    .replace(/^(https?:\/\/)www\./i, '$1')
    .replace(/^(https?:\/\/[^/]+)$/i, '$1/')
    .replace(/\/+$/g, '');
  return normalizedBase + (keptParams.length ? '?' + keptParams.join('&') : '');
}

function domainOf(input) {
  const match = String(input || '').match(/^[a-z]+:\/\/([^/?#]+)/i);
  return match ? match[1].toLowerCase().replace(/^www\./, '') : '';
}

function fallbackKey(title, deadline, domain) {
  return [
    String(title || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim().slice(0, 120),
    deadline || '',
    domain || '',
  ].join('|');
}

function sourceType(url) {
  const host = domainOf(url);
  if (host.includes('instagram') || host.includes('facebook')) return 'Social indexed';
  if (host.includes('museum')) return 'Museum';
  if (host.includes('gallery')) return 'Gallery';
  if (host.includes('festival')) return 'Festival';
  if (knownSourceHints.some((hint) => host.includes(hint))) return 'Aggregator';
  return 'Search result';
}

function normalizeDate(value) {
  if (!value) return null;
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return null;
  return parsed.toISOString().slice(0, 10);
}

function isPastDate(dateString) {
  if (!dateString) return false;
  return dateString < TODAY;
}

function truncate(value, max) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  return text.length > max ? text.slice(0, max - 1) + '...' : text;
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function remainingRunMs() {
  return AI_TIME_BUDGET_MS - (Date.now() - RUN_STARTED_AT);
}

function ensureRunBudget() {
  if (remainingRunMs() <= 0) {
    throw new Error('AI time budget exhausted before n8n 300s task timeout');
  }
  if (aiRequestsUsed >= AI_MAX_REQUESTS_PER_RUN) {
    throw new Error('AI request budget exhausted for this run');
  }
}

function shouldRunDiscovery() {
  if (DISCOVERY_MODE === 'daily') return true;
  if (DISCOVERY_MODE === 'manual') return false;
  if (DISCOVERY_MODE === 'weekly') return new Date().getDay() === 1;
  return false;
}

async function braveSearch(query) {
  if (!BRAVE_SEARCH_API_KEY || String(BRAVE_SEARCH_API_KEY).startsWith('PASTE_')) return [];
  const body = await requestJson('https://api.search.brave.com/res/v1/web/search?q=' + encodeURIComponent(query) + '&count=' + encodeURIComponent(String(MAX_RESULTS_PER_QUERY)), {
    method: 'GET',
    headers: {
      Accept: 'application/json',
      'X-Subscription-Token': BRAVE_SEARCH_API_KEY,
    },
  });
  return ((body.web && body.web.results) || []).map((result) => ({
    title: result.title || '',
    url: result.url || '',
    snippet: result.description || result.extra_snippets && result.extra_snippets.join(' ') || '',
    provider: 'Brave',
    score: 0,
  }));
}

async function serpApiSearch(query) {
  if (!SERPAPI_API_KEY || String(SERPAPI_API_KEY).startsWith('PASTE_')) return [];
  const body = await requestJson('https://serpapi.com/search.json?engine=google&q=' + encodeURIComponent(query) + '&num=' + encodeURIComponent(String(MAX_RESULTS_PER_QUERY)) + '&api_key=' + encodeURIComponent(SERPAPI_API_KEY), {
    method: 'GET',
  });
  return (body.organic_results || []).map((result) => ({
    title: result.title || '',
    url: result.link || '',
    snippet: result.snippet || '',
    provider: 'SerpAPI',
    score: result.position ? 1 / result.position : 0,
  }));
}

async function tavilySearch(query) {
  if (!TAVILY_API_KEY || String(TAVILY_API_KEY).startsWith('PASTE_')) return [];
  return requestJson('https://api.tavily.com/search', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      api_key: TAVILY_API_KEY,
      query,
      search_depth: 'advanced',
      max_results: MAX_RESULTS_PER_QUERY,
      include_answer: false,
      include_raw_content: false,
      topic: 'general',
      days: 30,
    }),
  }).then((body) => (body.results || []).map((result) => ({
    title: result.title || '',
    url: result.url || '',
    snippet: result.content || result.snippet || '',
    provider: 'Tavily',
    score: result.score || 0,
  })));
}

async function providerSearch(query) {
  let results = [];
  try {
    results = await braveSearch(query);
  } catch (error) {
    results = [];
  }
  if (results.length >= MIN_RESULTS_BEFORE_FALLBACK) return results;

  try {
    const fallback = await serpApiSearch(query);
    if (fallback.length) results = results.concat(fallback);
  } catch (error) {}
  if (results.length >= MIN_RESULTS_BEFORE_FALLBACK) return results;

  try {
    const fallback = await tavilySearch(query);
    if (fallback.length) results = results.concat(fallback);
  } catch (error) {}
  return results;
}

async function httpFallbackText(url) {
  try {
    const text = await httpRawText(url);
    return truncate(text
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&'), 12000);
  } catch {
    return '';
  }
}

async function httpRawText(url) {
  return httpRequest({
      method: 'GET',
      url,
      headers: {
        'User-Agent': 'Mozilla/5.0 n8n photography open call monitor',
        Accept: 'text/html,application/xhtml+xml,text/plain;q=0.9,*/*;q=0.8',
      },
      json: false,
    });
}

function absoluteUrl(href, baseUrl) {
  const value = String(href || '').trim();
  if (!value || value.startsWith('#') || value.startsWith('mailto:') || value.startsWith('tel:') || value.startsWith('javascript:')) return '';
  if (/^https?:\/\//i.test(value)) return value;
  const baseMatch = String(baseUrl || '').match(/^(https?:\/\/[^/]+)(\/.*)?$/i);
  if (!baseMatch) return '';
  if (value.startsWith('/')) return baseMatch[1] + value;
  const basePath = (baseMatch[2] || '/').replace(/\/[^/]*$/, '/');
  return baseMatch[1] + basePath + value;
}

function extractCandidateLinks(html, sourceUrl) {
  const out = [];
  const seen = {};
  const pattern = /<a\b[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
  let match;
  while ((match = pattern.exec(String(html || ''))) && out.length < DIRECT_LINK_LIMIT_PER_SOURCE) {
    const href = absoluteUrl(match[1], sourceUrl);
    const text = match[2].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    const combined = (href + ' ' + text).toLowerCase();
    const looksRelevant = /open.?call|call.?for.?entry|submission|submit|deadline|photography|photo|contest|award|grant|opportunit/.test(combined);
    if (!href || seen[canonicalize(href)] || !looksRelevant) continue;
    seen[canonicalize(href)] = true;
    out.push({
      query: 'direct-source',
      title: text || href,
      url: href,
      canonical: canonicalize(href),
      snippet: text,
      provider: 'Direct',
      score: 0,
    });
  }
  return out;
}

async function extractWithGemini(candidate, pageText) {
  const system = [
    'You extract and classify photography open calls for an Airtable automation.',
    'Return strict JSON only. Do not use markdown.',
    'The user wants current, free-to-submit photography/photo/video/multimedia visual open calls with electronic submission.',
    'Required fees disqualify. Optional donations, sales commissions, and non-required production costs do not disqualify.',
    'If deadline is missing or unclear, set deadline to null and explain in rejection_reason.',
  ].join(' ');
  const user = JSON.stringify({
    today: TODAY,
    url: candidate.url,
    title: candidate.title,
    searchSnippet: candidate.snippet,
    pageText,
    expectedSchema: {
      title: 'string',
      is_photo_open_call: 'boolean',
      is_free: 'boolean',
      is_online_submission: 'boolean',
      deadline: 'YYYY-MM-DD or null',
      summary: '1-3 concise sentences',
      fee_status: 'Free | No required fee | Unknown | Paid required fee',
      submission_type: 'Online | Email | Platform | Unknown',
      confidence: 'number 0..1',
      rejection_reason: 'string or empty',
    },
  });
  const endpoint = 'https://generativelanguage.googleapis.com/v1beta/models/' + encodeURIComponent(AI_MODEL) + ':generateContent';
  const responseSchema = {
    type: 'OBJECT',
    properties: {
      title: { type: 'STRING' },
      is_photo_open_call: { type: 'BOOLEAN' },
      is_free: { type: 'BOOLEAN' },
      is_online_submission: { type: 'BOOLEAN' },
      deadline: { type: 'STRING', nullable: true },
      summary: { type: 'STRING' },
      fee_status: { type: 'STRING', enum: ['Free', 'No required fee', 'Unknown', 'Paid required fee'] },
      submission_type: { type: 'STRING', enum: ['Online', 'Email', 'Platform', 'Unknown'] },
      confidence: { type: 'NUMBER' },
      rejection_reason: { type: 'STRING' },
    },
    required: [
      'title',
      'is_photo_open_call',
      'is_free',
      'is_online_submission',
      'deadline',
      'summary',
      'fee_status',
      'submission_type',
      'confidence',
      'rejection_reason',
    ],
  };

  ensureRunBudget();
  aiRequestsUsed += 1;
  const body = await requestJson(endpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-goog-api-key': GEMINI_API_KEY,
    },
    body: JSON.stringify({
      contents: [
        {
          role: 'user',
          parts: [
            { text: system + '\n\nInput:\n' + user },
          ],
        },
      ],
      generationConfig: {
        temperature: 0,
        response_mime_type: 'application/json',
        response_schema: responseSchema,
      },
    }),
  });
  const content = body.candidates
    && body.candidates[0]
    && body.candidates[0].content
    && body.candidates[0].content.parts
    && body.candidates[0].content.parts[0]
    && body.candidates[0].content.parts[0].text;
  return parseJsonFromModel(content || '{}');
}

function parseJsonFromModel(content) {
  let text = String(content || '').trim();
  const fence = String.fromCharCode(96, 96, 96);
  if (text.startsWith(fence)) {
    text = text.replace(new RegExp('^' + fence + '(?:json)?', 'i'), '').replace(new RegExp(fence + '$', 'i'), '').trim();
  }
  try {
    return JSON.parse(text);
  } catch (error) {
    const objectText = firstBalancedJsonObject(text);
    if (objectText) return JSON.parse(objectText);
    throw error;
  }
}

function firstBalancedJsonObject(text) {
  const start = text.indexOf('{');
  if (start < 0) return '';
  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let index = start; index < text.length; index++) {
    const char = text[index];
    if (escaped) {
      escaped = false;
      continue;
    }
    if (char === '\\') {
      escaped = true;
      continue;
    }
    if (char === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;
    if (char === '{') depth += 1;
    if (char === '}') {
      depth -= 1;
      if (depth === 0) return text.slice(start, index + 1);
    }
  }
  return '';
}

async function airtable(path, options = {}) {
  return requestJson('https://api.airtable.com/v0/' + AIRTABLE_BASE_ID + path, {
    ...options,
    headers: {
      Authorization: 'Bearer ' + AIRTABLE_API_KEY,
      'Content-Type': 'application/json',
      ...(options.headers || {}),
    },
  });
}

async function listAirtableRecords(tableName, filterByFormula) {
  const records = [];
  let offset = undefined;
  do {
    const params = ['pageSize=100'];
    if (filterByFormula) params.push('filterByFormula=' + encodeURIComponent(filterByFormula));
    if (offset) params.push('offset=' + encodeURIComponent(offset));
    const body = await airtable('/' + encodeURIComponent(tableName) + '?' + params.join('&'), { method: 'GET' });
    records.push(...(body.records || []));
    offset = body.offset;
  } while (offset);
  return records;
}

async function batchPatch(tableName, records, mergeField) {
  const chunks = [];
  for (let i = 0; i < records.length; i += 10) chunks.push(records.slice(i, i + 10));
  const responses = [];
  for (const chunk of chunks) {
    const body = { records: chunk };
    if (mergeField) body.performUpsert = { fieldsToMergeOn: [mergeField] };
    responses.push(await airtable('/' + encodeURIComponent(tableName), {
      method: 'PATCH',
      body: JSON.stringify(body),
    }));
  }
  return responses;
}

function stripSourceTrackingFields(record) {
  const fields = { ...(record.fields || {}) };
  delete fields['Last Discovery Checked'];
  delete fields['Last Direct Checked'];
  delete fields['Discovery Provider'];
  delete fields['Provider Cost Class'];
  return { ...record, fields };
}

async function batchPatchSources(records, mergeField) {
  try {
    return await batchPatch('Sources', records, mergeField);
  } catch (error) {
    const message = error.message || String(error);
    if (!message.includes('422')) throw error;
    try {
      return await batchPatch('Sources', records.map(stripSourceTrackingFields), mergeField);
    } catch (fallbackError) {
      throw new Error('Airtable rejected Sources update even after removing optional tracking fields. Run setup-airtable.json once to create the latest Sources schema. Original error: ' + message + '. Fallback error: ' + (fallbackError.message || String(fallbackError)));
    }
  }
}

const allOpenCallRecords = await listAirtableRecords('Open Calls');
const existingOpenCallsByCanonical = new Map();
const existingOpenCallsByFallback = new Map();
for (const record of allOpenCallRecords) {
  const fields = record.fields || {};
  if (fields['Canonical URL']) existingOpenCallsByCanonical.set(canonicalize(fields['Canonical URL']), record);
  const key = fallbackKey(fields.Title, fields.Deadline, fields.Source);
  if (key !== '||') existingOpenCallsByFallback.set(key, record);
}

const allSourceRecords = await listAirtableRecords('Sources');
const existingSourcesByKey = new Map();
for (const record of allSourceRecords) {
  const fields = record.fields || {};
  const key = fields['Source Key'] || fields.Domain;
  if (key) existingSourcesByKey.set(key, record);
}

const expiredCandidates = allOpenCallRecords.filter((record) => {
  const status = record.fields && record.fields.Status;
  return status === 'Active' || status === 'Needs review';
});
const expiredUpdates = expiredCandidates
  .filter((record) => isPastDate(record.fields && record.fields.Deadline))
  .map((record) => ({ id: record.id, fields: { Status: 'Expired', 'Last Checked': TODAY } }));
if (expiredUpdates.length) await batchPatch('Open Calls', expiredUpdates);

const activeSources = allSourceRecords
  .filter((record) => {
    const fields = record.fields || {};
    return (fields.Status === 'Approved' || fields.Status === 'Candidate') && fields['Source URL'];
  })
  .slice(0, SOURCE_RECHECK_LIMIT);

const sourceDirectUpdates = [];
const directSourceResults = [];
for (const sourceRecord of activeSources) {
  const fields = sourceRecord.fields || {};
  const sourceUrl = fields['Source URL'];
  directSourceResults.push({
    query: 'direct-source',
    title: fields.Domain || sourceUrl,
    url: sourceUrl,
    canonical: canonicalize(sourceUrl),
    snippet: 'Known Airtable source direct recheck',
    provider: 'Direct',
    score: 0,
  });
  try {
    const html = await httpRawText(sourceUrl);
    directSourceResults.push(...extractCandidateLinks(html, sourceUrl));
    sourceDirectUpdates.push({
      id: sourceRecord.id,
      fields: {
        'Last Direct Checked': TODAY,
        'Discovery Provider': 'Direct',
        'Provider Cost Class': 'Free direct HTTP',
      },
    });
  } catch (error) {
    sourceDirectUpdates.push({
      id: sourceRecord.id,
      fields: {
        'Last Direct Checked': TODAY,
      },
    });
  }
}
if (sourceDirectUpdates.length) await batchPatchSources(sourceDirectUpdates);

const discoveryResults = [];
const discoveryShouldRun = DISCOVERY_MODE !== 'manual' && (shouldRunDiscovery() || activeSources.length === 0);
if (discoveryShouldRun && DISCOVERY_QUERY_LIMIT > 0) {
  for (const query of searchQueries.slice(0, DISCOVERY_QUERY_LIMIT)) {
    const results = await providerSearch(query);
    for (const result of results) {
      const url = result.url || '';
      const canonical = canonicalize(url);
      if (!url || rejectHostFragments.some((fragment) => canonical.includes(fragment))) continue;
      discoveryResults.push({
        query,
        title: result.title || '',
        url,
        canonical,
        snippet: result.snippet || '',
        provider: result.provider || 'Search',
        score: result.score || 0,
      });
    }
  }
}

const searchResults = directSourceResults.concat(discoveryResults);

const byCanonical = new Map();
for (const result of searchResults) {
  if (!byCanonical.has(result.canonical)) byCanonical.set(result.canonical, result);
}
const candidates = [...byCanonical.values()].slice(0, MAX_CANDIDATES);

const openCallUpserts = [];
const openCallUpdates = [];
const sourceRecordsByKey = new Map();
const rejected = [];
let aiRateLimitFailures = 0;
let aiDisabledReason = '';

function queueSource(candidate, status, confidence) {
  const domain = domainOf(candidate.url);
  const existingSource = existingSourcesByKey.get(domain);
  const existingSourceFields = (existingSource && existingSource.fields) || {};
  const computedSourceStatus = status === 'Active' || status === 'Needs review' ? 'Candidate' : 'Dormant';
  const preservedSourceStatus = ['Approved', 'Rejected'].includes(existingSourceFields.Status)
    ? existingSourceFields.Status
    : computedSourceStatus;
  const provider = candidate.provider || 'Manual';
  const providerCostClass = provider === 'Direct'
    ? 'Free direct HTTP'
    : provider === 'Brave'
      ? 'Low-cost search'
      : 'Fallback search';
  sourceRecordsByKey.set(domain, {
    fields: {
      'Source Key': domain,
      'Source URL': 'https://' + domain,
      Domain: domain,
      'Source Type': sourceType(candidate.url),
      Status: preservedSourceStatus,
      Confidence: confidence,
      'First Seen': existingSourceFields['First Seen'] || TODAY,
      'Last Seen': TODAY,
      ...(provider === 'Direct' ? { 'Last Direct Checked': TODAY } : { 'Last Discovery Checked': TODAY }),
      'Discovery Provider': provider,
      'Provider Cost Class': providerCostClass,
      'Hit Count': Number(existingSourceFields['Hit Count'] || 0) + 1,
    },
  });
  return domain;
}

function queueOpenCall(candidate, fields, deadline) {
  const domain = fields.Source || domainOf(candidate.url);
  const existingOpenCall = existingOpenCallsByCanonical.get(candidate.canonical)
    || existingOpenCallsByFallback.get(fallbackKey(fields.Title, deadline, domain));
  const existingOpenCallFields = (existingOpenCall && existingOpenCall.fields) || {};
  const mergedFields = {
    ...fields,
    'First Seen': existingOpenCallFields['First Seen'] || TODAY,
    'Last Checked': TODAY,
  };
  if (existingOpenCall) {
    openCallUpdates.push({ id: existingOpenCall.id, fields: mergedFields });
  } else {
    openCallUpserts.push({ fields: mergedFields });
  }
}

function queueNeedsReviewCandidate(candidate, reason) {
  const domain = queueSource(candidate, 'Needs review', 0);
  queueOpenCall(candidate, {
    Title: truncate(candidate.title || candidate.url, 250),
    URL: candidate.url,
    'Canonical URL': candidate.canonical,
    Summary: truncate(candidate.snippet || 'AI could not classify this candidate. Review the linked page manually.', 2000),
    'Fee Status': 'Unknown',
    'Submission Type': 'Unknown',
    Source: domain,
    Confidence: 0,
    Status: 'Needs review',
    'Rejection Reason': reason,
  }, null);
}

for (const candidate of candidates) {
  if (aiDisabledReason) {
    queueNeedsReviewCandidate(candidate, aiDisabledReason);
    continue;
  }
  if (remainingRunMs() <= 15000 || aiRequestsUsed >= AI_MAX_REQUESTS_PER_RUN) {
    aiDisabledReason = 'Skipped AI extraction because this n8n run reached its time/request budget. Review manually or rerun later.';
    queueNeedsReviewCandidate(candidate, aiDisabledReason);
    continue;
  }
  let pageText = await httpFallbackText(candidate.url);
  if (!pageText && !candidate.snippet) {
    rejected.push({ url: candidate.url, reason: 'No page text or useful snippet available' });
    continue;
  }

  let extracted;
  try {
    extracted = await extractWithGemini(candidate, pageText || candidate.snippet);
  } catch (error) {
    const message = error.message || String(error);
    if (message.includes('429') || message.toLowerCase().includes('rate limit')) {
      aiRateLimitFailures += 1;
      queueNeedsReviewCandidate(candidate, 'Gemini rate-limited this run. Review manually or rerun later.');
      aiDisabledReason = 'Skipped Gemini extraction after a rate-limit response. Review manually or rerun later.';
    } else {
      queueNeedsReviewCandidate(candidate, 'Gemini extraction failed. Review manually. Error: ' + truncate(message, 500));
    }
    rejected.push({ url: candidate.url, reason: 'Gemini extraction failed: ' + message });
    continue;
  }

  const deadline = normalizeDate(extracted.deadline);
  const confidence = Math.max(0, Math.min(1, Number(extracted.confidence || 0)));
  const isRelevant = extracted.is_photo_open_call === true && extracted.is_free === true && extracted.is_online_submission === true;
  const isExpired = deadline ? isPastDate(deadline) : false;
  let status = 'Rejected';
  let rejectionReason = extracted.rejection_reason || '';

  if (isRelevant && !isExpired && deadline && confidence >= CONFIRMED_THRESHOLD) {
    status = 'Active';
  } else if (isRelevant && !isExpired && (!deadline || confidence < CONFIRMED_THRESHOLD)) {
    status = 'Needs review';
    if (!deadline) rejectionReason = rejectionReason || 'Missing or unclear deadline';
    if (confidence < CONFIRMED_THRESHOLD) rejectionReason = rejectionReason || 'Confidence below threshold';
  } else if (isExpired) {
    status = 'Expired';
    rejectionReason = rejectionReason || 'Deadline is in the past';
  } else {
    rejectionReason = rejectionReason || 'Not a current free photography open call with online submission';
  }

  const domain = queueSource(candidate, status, confidence);

  if (status === 'Rejected') {
    rejected.push({ url: candidate.url, reason: rejectionReason });
    continue;
  }

  const finalTitle = truncate(extracted.title || candidate.title || candidate.url, 250);
  queueOpenCall(candidate, {
      Title: finalTitle,
      URL: candidate.url,
      'Canonical URL': candidate.canonical,
      ...(deadline ? { Deadline: deadline } : {}),
      Summary: truncate(extracted.summary || candidate.snippet || '', 2000),
      'Fee Status': extracted.fee_status || (extracted.is_free ? 'No required fee' : 'Unknown'),
      'Submission Type': extracted.submission_type || 'Unknown',
      Source: domain,
      Confidence: confidence,
      Status: status,
      'Rejection Reason': rejectionReason,
    }, deadline);
}

if (sourceRecordsByKey.size) {
  await batchPatchSources([...sourceRecordsByKey.values()], 'Source Key');
}
if (openCallUpdates.length) {
  await batchPatch('Open Calls', openCallUpdates);
}
if (openCallUpserts.length) {
  await batchPatch('Open Calls', openCallUpserts, 'Canonical URL');
}

const providerCounts = {};
for (const result of searchResults) {
  const provider = result.provider || 'Unknown';
  providerCounts[provider] = (providerCounts[provider] || 0) + 1;
}

return [{
  json: {
    ok: true,
    date: TODAY,
    discoveryMode: DISCOVERY_MODE,
    discoveryRan: discoveryShouldRun,
    discoveryQueryLimit: DISCOVERY_QUERY_LIMIT,
    searchedQueries: discoveryShouldRun ? Math.min(DISCOVERY_QUERY_LIMIT, searchQueries.length) : 0,
    activeSourcesChecked: activeSources.length,
    rawResults: searchResults.length,
    directSourceResults: directSourceResults.length,
    discoveryResults: discoveryResults.length,
    providerCounts,
    uniqueCandidates: candidates.length,
    savedOpenCalls: openCallUpdates.length + openCallUpserts.length,
    updatedOpenCalls: openCallUpdates.length,
    upsertedOpenCalls: openCallUpserts.length,
    upsertedSources: sourceRecordsByKey.size,
    expiredUpdated: expiredUpdates.length,
    rejectedCount: rejected.length,
    rejectedSample: rejected.slice(0, 10),
    confidenceThreshold: CONFIRMED_THRESHOLD,
    aiProvider: 'gemini',
    model: AI_MODEL,
    aiRateLimitFailures,
    aiDisabledReason,
    aiRequestsUsed,
  },
}];
